        const suggested = suggestedSecondaryTaskSettingsV55137(selectedSubject, detailSelect?.value || "", activitySelect?.value || "");
        setInputValue('input[name="difficulty"]', suggested.difficulty);
        setInputValue('input[name="priority"]', suggested.priority);
        setInputValue('input[name="estimated_minutes"]', suggested.minutes);
        setSuggestedRepeat(suggested.repeat);

        const notesInput = document.getElementById("notesInput");
